def hamiltonian_path(graph):
    V = len(graph)
    path = [-1] * V

    for start_node in range(V):
        path[0] = start_node
        if _hamiltonian_path_util(graph, path, 1):
            return path
        path[0] = -1 # Reset for next attempt

    return None

def _hamiltonian_path_util(graph, path, pos):
    V = len(graph)

    if pos == V:
        return True

    for v in range(V):
        if _is_safe(v, graph, path, pos):
            path[pos] = v
            if _hamiltonian_path_util(graph, path, pos + 1):
                return True
            path[pos] = -1 # Backtrack

    return False

def _is_safe(v, graph, path, pos):
    if graph[path[pos - 1]][v] == 0:
        return False

    for i in range(pos):
        if path[i] == v:
            return False

    return True
